var PdfPrinter = require("pdfmake");

// ----- Brand palette (NYC government blue + complementary accents) -----
var NYCHA_NAVY    = "#003C71";
var NYCHA_NAVY_DK = "#00254A";
var NYCHA_GOLD    = "#C99700";
var TEXT_DARK     = "#1A1A1A";
var TEXT_MUTED    = "#5F6975";
var ROW_TINT      = "#F2F5FA";
var BORDER_LIGHT  = "#D6DCE5";

// ----- Helpers -----
function joinNonEmpty(parts, sep) {
    return parts
        .filter(function (x) { return x !== null && x !== undefined && String(x).trim() !== ""; })
        .join(sep || " ");
}

function hi(v) {
    var s = (v === null || v === undefined) ? "" : String(v);
    return { text: s.trim() === "" ? "\u2014" : s, style: "highlight" };
}

function yesNo(flag) {
    var u = String(flag || "").toUpperCase();
    if (u === "Y" || u === "YES" || u === "TRUE") return "Yes";
    if (u === "N" || u === "NO"  || u === "FALSE") return "No";
    return "\u2014";
}

function titleCase(v) {
    if (v === null || v === undefined) return "";
    var s = String(v).trim().toLowerCase().replace(/_/g, " ");
    return s.replace(/\b([a-z])/g, function (m) { return m.toUpperCase(); });
}

function fmtMoney(v) {
    if (v === null || v === undefined || v === "") return "";
    var n = parseFloat(v);
    if (isNaN(n)) return String(v);
    var s = n.toFixed(2);
    var parts = s.split(".");
    parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    return "$" + parts.join(".");
}

function fmtNum(v) {
    if (v === null || v === undefined || v === "") return "";
    var n = parseFloat(v);
    if (isNaN(n)) return String(v);
    return n % 1 === 0 ? String(Math.round(n)) : String(n);
}

function fmtDate(v) {
    if (!v) return "";
    var s = String(v);
    // Accept YYYY-MM-DD, or anything Date can parse.
    var d = new Date(s);
    if (isNaN(d.getTime())) return s;
    var months = ["January","February","March","April","May","June","July","August","September","October","November","December"];
    return months[d.getMonth()] + " " + d.getDate() + ", " + d.getFullYear();
}

// Numbered, accented section heading: 3pt navy bar | roman numeral + title.
function sectionHeader(roman, title) {
    return {
        table: {
            widths: [3, "*"],
            body: [[
                { text: "", fillColor: NYCHA_NAVY },
                { text: roman + ".  " + title, style: "sectionHeader" }
            ]]
        },
        layout: {
            hLineWidth: function () { return 0; },
            vLineWidth: function () { return 0; },
            paddingLeft:  function (i) { return i === 0 ? 0 : 9; },
            paddingRight: function () { return 0; },
            paddingTop:   function () { return 3; },
            paddingBottom:function () { return 3; }
        },
        margin: [0, 16, 0, 6]
    };
}

// Standard data table layout (1-col label / 1-col value, zebra-striped).
var zebraLayout = {
    fillColor: function (rowIndex) {
        return (rowIndex % 2 === 0) ? ROW_TINT : null;
    },
    hLineWidth: function () { return 0.5; },
    vLineWidth: function () { return 0; },
    hLineColor: function () { return BORDER_LIGHT; },
    paddingTop:    function () { return 5; },
    paddingBottom: function () { return 5; },
    paddingLeft:   function () { return 9; },
    paddingRight:  function () { return 9; }
};

// ----- Pull data the plugin steps loaded -----
var t = output["_tenant"]   || {};
var p = output["_property"] || {};
var tenantIdNum   = parseInt(input["tenantID"],   10) || "";
var propertyIdNum = parseInt(input["propertyID"], 10) || "";

console.log("tenancyPDF: tenant=",   JSON.stringify(t));
console.log("tenancyPDF: property=", JSON.stringify(p));

// ----- Computed display strings -----
var tenantFullName        = joinNonEmpty([t.tfname, t.tmname, t.tlname], " ");
var tenantCurrentAddrLine = joinNonEmpty([t.taddr1, t.taddr2], " ");
var tenantCityStateZip    = joinNonEmpty([t.tcity, joinNonEmpty([t.tstate, t.tzip], " ")], ", ");
var tenantFullAddress     = joinNonEmpty([tenantCurrentAddrLine, tenantCityStateZip], ", ");

var propertyStreet     = joinNonEmpty([p.pstrno, p.pstrnam], " ");
var propertyUnitLabel  = p.punit ? "Unit " + p.punit : "";
var propertyAddrLine   = joinNonEmpty([propertyStreet, propertyUnitLabel], ", ");
var propertyCityRegion = joinNonEmpty([p.pboro, p.pcity], ", ");
var propertyStateZip   = joinNonEmpty([p.pstate, p.pzip], " ");
var propertyFullAddress= joinNonEmpty([propertyAddrLine, propertyCityRegion, propertyStateZip], ", ");

var today = new Date();
var pad2 = function (n) { return (n < 10 ? "0" : "") + n; };
var todayStrISO = today.getFullYear() + "-" + pad2(today.getMonth() + 1) + "-" + pad2(today.getDate());
var todayStrLong = fmtDate(todayStrISO);
var docRef = "NYCHA-LSE-" + (tenantIdNum || "X") + "-" + (propertyIdNum || "X") + "-" + today.getFullYear() + pad2(today.getMonth() + 1) + pad2(today.getDate());

var moveInDate = p.pavaild ? fmtDate(p.pavaild) : "the Move-In Date";
var monthlyRent = fmtMoney(p.prent);
var annualRent  = (function () {
    var n = parseFloat(p.prent);
    if (isNaN(n)) return "";
    return fmtMoney(n * 12);
})();
var securityDeposit = fmtMoney(p.prent);   // standard practice: 1 month equivalent
var tenantIncome = fmtMoney(t.tincome);
var kitchenLabel = titleCase(p.pkitchn);
var laundryLabel = (function () {
    var u = String(p.plaundr || "").toUpperCase().replace(/_/g, " ");
    if (u === "IN UNIT")  return "In-Unit";
    if (u === "HOOKUPS")  return "Hookups Provided";
    if (u === "BUILDING") return "Shared (In Building)";
    if (u === "NONE")     return "Not Available";
    return titleCase(p.plaundr);
})();
var petPolicy = titleCase(p.ppets);

// ============================================================
// PDF DOCUMENT
// ============================================================
var fonts = {
    Helvetica: {
        normal:      "Helvetica",
        bold:        "Helvetica-Bold",
        italics:     "Helvetica-Oblique",
        bolditalics: "Helvetica-BoldOblique"
    }
};
var printer = new PdfPrinter(fonts);

var docDef = {
    pageSize: "LETTER",
    pageMargins: [54, 80, 54, 60],
    defaultStyle: { font: "Helvetica", fontSize: 10, lineHeight: 1.35, color: TEXT_DARK },

    images: {
        nychaLogo: "data:image/png;base64,"
    },

    // ---- Running header (suppressed on cover) ----
    header: function (currentPage) {
        if (currentPage === 1) return undefined;
        return {
            margin: [54, 28, 54, 0],
            stack: [
                {
                    columns: [
                        { image: "nychaLogo", width: 18 },
                        { width: "*", text: "Residential Lease Agreement", fontSize: 8, color: TEXT_MUTED, margin: [8, 4, 0, 0] },
                        { width: "auto", text: docRef, fontSize: 8, color: TEXT_MUTED, alignment: "right", margin: [0, 4, 0, 0] }
                    ]
                },
                { canvas: [{ type: "line", x1: 0, y1: 5, x2: 488, y2: 5, lineWidth: 0.5, lineColor: BORDER_LIGHT }] }
            ]
        };
    },

    // ---- Running footer (all pages) ----
    footer: function (currentPage, pageCount) {
        return {
            margin: [54, 0, 54, 22],
            stack: [
                { canvas: [{ type: "line", x1: 0, y1: 0, x2: 488, y2: 0, lineWidth: 0.5, lineColor: BORDER_LIGHT }] },
                {
                    margin: [0, 5, 0, 0],
                    columns: [
                        { text: "New York City Housing Authority", fontSize: 7.5, color: TEXT_MUTED },
                        { text: "CONFIDENTIAL \u2014 Authorized Use Only", fontSize: 7.5, color: TEXT_MUTED, alignment: "center" },
                        { text: "Page " + currentPage + " of " + pageCount, fontSize: 7.5, color: TEXT_MUTED, alignment: "right" }
                    ]
                }
            ]
        };
    },

    content: [
        // ============ COVER PAGE ============
        { text: "", margin: [0, 36, 0, 0] },
        {
            // Real NYCHA logo (registered in docDef.images), centered with flex spacers
            columns: [
                { width: "*", text: "" },
                { image: "nychaLogo", width: 100 },
                { width: "*", text: "" }
            ],
            margin: [0, 0, 0, 12]
        },
        // Gold accent rule
        { canvas: [{ type: "rect", x: 202, y: 0, w: 100, h: 2, color: NYCHA_GOLD }], margin: [0, 0, 0, 32] },

        { text: "RESIDENTIAL LEASE", style: "coverTitle" },
        { text: "AGREEMENT", style: "coverTitle", margin: [0, -4, 0, 14] },
        { text: "by and between the New York City Housing Authority", style: "coverSubtitle" },
        { text: "and the undersigned Tenant identified below", style: "coverSubtitle", margin: [0, 0, 0, 22] },

        // Cover summary panel
        {
            table: {
                widths: [120, "*"],
                body: [
                    [{ text: "DOCUMENT REFERENCE", style: "coverLabel" }, { text: docRef, style: "coverValueBold" }],
                    [{ text: "EFFECTIVE DATE",      style: "coverLabel" }, hi(todayStrLong)],
                    [{ text: "TENANT",              style: "coverLabel" }, hi(tenantFullName)],
                    [{ text: "PREMISES",            style: "coverLabel" }, hi(propertyFullAddress)],
                    [{ text: "MONTHLY RENT",        style: "coverLabel" }, hi(monthlyRent)],
                    [{ text: "LEASE COMMENCEMENT",  style: "coverLabel" }, hi(moveInDate)]
                ]
            },
            layout: {
                fillColor: function (rowIndex) { return (rowIndex % 2 === 0) ? ROW_TINT : null; },
                hLineWidth: function (i, node) { return (i === 0 || i === node.table.body.length) ? 1 : 0.5; },
                vLineWidth: function () { return 0; },
                hLineColor: function () { return BORDER_LIGHT; },
                paddingTop:    function () { return 7; },
                paddingBottom: function () { return 7; },
                paddingLeft:   function () { return 10; },
                paddingRight:  function () { return 10; }
            },
            margin: [40, 0, 40, 22]
        },

        { text: "THIS LEASE CONTAINS LEGAL AND BINDING OBLIGATIONS. READ CAREFULLY BEFORE SIGNING.", fontSize: 9, bold: true, color: NYCHA_NAVY, alignment: "center", margin: [0, 0, 0, 0] },
        { text: "For questions, contact your NYCHA Property Management Office.", fontSize: 9, italics: true, color: TEXT_MUTED, alignment: "center" },

        // ============ MAIN AGREEMENT (starts on its own page) ============
        {
            pageBreak: "before",
            text: [
                "This Residential Lease Agreement (the ", { text: "\"Agreement\"", italics: true }, ") is made and entered into as of ",
                hi(todayStrLong),
                " (the ", { text: "\"Effective Date\"", italics: true }, "), by and between the ",
                { text: "NEW YORK CITY HOUSING AUTHORITY", bold: true }, " (the ", { text: "\"Authority\"", italics: true }, " or ", { text: "\"Landlord\"", italics: true }, "), a public benefit corporation organized under the laws of the State of New York, and the tenant identified below (the ", { text: "\"Tenant\"", italics: true }, "). The Authority and the Tenant are sometimes referred to individually as a ", { text: "\"Party\"", italics: true }, " and collectively as the ", { text: "\"Parties.\"", italics: true }
            ],
            margin: [0, 0, 0, 4]
        },

        sectionHeader("I", "PARTIES TO THIS AGREEMENT"),
        {
            text: [
                "The Tenant is ", hi(tenantFullName), ", currently of ", hi(tenantFullAddress),
                ". The Tenant represents and warrants that the information provided in this Agreement is true and complete in all material respects."
            ]
        },

        sectionHeader("II", "PREMISES AND PROPERTY DETAILS"),
        {
            text: [
                "Subject to the terms and conditions set forth herein, the Authority hereby leases to the Tenant, and the Tenant hereby leases from the Authority, the residential premises located at ",
                hi(propertyFullAddress), " (the ", { text: "\"Premises\"", italics: true }, "). The Premises are further described in the table below."
            ]
        },
        {
            margin: [0, 8, 0, 0],
            table: {
                widths: [180, "*"],
                body: [
                    ["Bedrooms",            hi(fmtNum(p.pbeds))],
                    ["Bathrooms",           hi(fmtNum(p.pbaths))],
                    ["Approximate Sq. Ft.", hi(fmtNum(p.psqft))],
                    ["Kitchen Appointment", hi(kitchenLabel)],
                    ["Laundry",             hi(laundryLabel)],
                    ["Heat Included",       hi(yesNo(p.pheat))],
                    ["Utilities Included",  hi(yesNo(p.putils))],
                    ["Pet Policy",          hi(petPolicy)]
                ]
            },
            layout: zebraLayout
        },

        sectionHeader("III", "TERM"),
        {
            text: [
                "The term of this Agreement (the ", { text: "\"Term\"", italics: true }, ") shall commence on ",
                hi(moveInDate), " (the ", { text: "\"Commencement Date\"", italics: true },
                ") and shall continue on a month-to-month basis thereafter unless and until terminated in accordance with Section XIII or as otherwise provided by applicable law. Tenant shall surrender the Premises at the expiration or earlier termination of the Term in the same condition as received, ordinary wear and tear excepted."
            ]
        },

        sectionHeader("IV", "RENT, SECURITY DEPOSIT, AND PAYMENTS"),
        {
            ol: [
                { text: ["\u00a0", { text: "Monthly Rent.", bold: true }, " Tenant shall pay to the Authority monthly rent in the amount of ", hi(monthlyRent), " (the ", { text: "\"Rent\"", italics: true }, "), in advance and without demand or offset, on or before the first (1st) day of each calendar month. Total annual base rent under this Agreement equals ", hi(annualRent), "."] },
                { text: ["\u00a0", { text: "Late Charges.", bold: true }, " Any Rent not received by the tenth (10th) day of the month in which it is due shall be subject to a late charge in the amount permitted by applicable law and the Authority's then-current published schedule of charges."] },
                { text: ["\u00a0", { text: "Security Deposit.", bold: true }, " Tenant shall deposit with the Authority the sum of ", hi(securityDeposit), " as security for Tenant's faithful performance of Tenant's obligations under this Agreement, to be held in accordance with New York General Obligations Law \u00a7 7-103 and returned, less lawful deductions, within the period required by law following the surrender of the Premises."] },
                { text: ["\u00a0", { text: "Method of Payment.", bold: true }, " Rent shall be paid by means designated by the Authority from time to time. Cash payments are not accepted."] }
            ]
        },

        sectionHeader("V", "UTILITIES, SERVICES, AND AMENITIES"),
        {
            text: [
                "Heat shall be ", hi(yesNo(p.pheat).toLowerCase() === "yes" ? "included in Rent" : "the responsibility of the Tenant"),
                ". Utilities (including electricity, gas, water, and sewer) shall be ", hi(yesNo(p.putils).toLowerCase() === "yes" ? "included in Rent" : "the responsibility of the Tenant"),
                ". The kitchen of the Premises is appointed at ", hi(kitchenLabel), " level. Laundry facilities are ", hi(laundryLabel), "."
            ]
        },
        {
            text: "Interruptions in utility or service that are beyond the reasonable control of the Authority shall not constitute a breach of this Agreement, provided that the Authority shall use commercially reasonable efforts to restore service.",
            margin: [0, 6, 0, 0]
        },

        sectionHeader("VI", "USE OF PREMISES; OCCUPANCY"),
        {
            text: [
                "The Premises shall be used solely as a private residence by the Tenant and the members of the Tenant's household as disclosed to the Authority on the application materials incorporated herein by reference. The disclosed household size is ",
                hi(fmtNum(t.thhsize)), " person(s). Tenant shall not use the Premises for any commercial, unlawful, or hazardous purpose, nor in any manner that would invalidate any insurance maintained on the Premises or building."
            ]
        },

        sectionHeader("VII", "TENANT'S OBLIGATIONS"),
        {
            ol: [
                "To keep the Premises clean, sanitary, and in good condition, and to dispose of all refuse and recyclables in accordance with applicable law and Authority rules.",
                "To pay Rent and all other sums due hereunder when due, without demand, deduction, or offset.",
                "To promptly notify the Authority in writing of any condition requiring repair, including any leak, mold, pest infestation, smoke- or carbon-monoxide-detector failure, or hazardous condition.",
                "To refrain from making any alteration, addition, or improvement to the Premises (including painting, drilling, or installation of fixtures) without the Authority's prior written consent.",
                "To comply with all applicable laws, ordinances, and regulations, and with all rules and regulations of the Authority and the building, as the same may be amended from time to time.",
                "To permit the Authority and its agents to enter the Premises in accordance with Section IX.",
                "To refrain from any conduct that unreasonably disturbs other residents or the peaceful enjoyment of their dwellings, and to be responsible for the conduct of all guests and invitees."
            ]
        },

        sectionHeader("VIII", "LANDLORD'S OBLIGATIONS"),
        {
            ol: [
                "To deliver the Premises in habitable condition and to maintain the Premises and the common areas of the building in compliance with the warranty of habitability set forth in New York Real Property Law \u00a7 235-b.",
                "To make all repairs to the structural components of the Premises and to building systems that the Authority is required by law to maintain.",
                "To respect the Tenant's right of quiet enjoyment of the Premises, subject to the Authority's reserved rights of entry under this Agreement and applicable law.",
                "To respond to written notices of needed repairs within a commercially reasonable time, with priority given to conditions affecting health or safety."
            ]
        },

        sectionHeader("IX", "ACCESS AND INSPECTION"),
        {
            text: "The Authority and its authorized representatives shall have the right to enter the Premises at reasonable times and upon at least twenty-four (24) hours' prior notice (except in the case of emergency, in which case no advance notice is required) for the purposes of inspection, repair, maintenance, pest control, showing to prospective tenants or contractors, or compliance with applicable law."
        },

        sectionHeader("X", "ASSIGNMENT AND SUBLETTING"),
        {
            text: [
                "Tenant shall not assign this Agreement, sublet the Premises in whole or in part, or permit occupancy of the Premises by any person not identified in the household composition disclosed to the Authority, without the prior written consent of the Authority, which consent may be granted or withheld in the Authority's sole discretion as permitted by law. Any purported assignment or sublease in violation of this Section shall be void and shall constitute a material default hereunder."
            ]
        },

        sectionHeader("XI", "PET POLICY"),
        {
            text: [
                "The pet policy applicable to the Premises is: ", hi(petPolicy),
                ". Tenants who are permitted to keep companion animals shall comply with the Authority's Pet Policy, including registration, weight and breed restrictions where applicable, and obligations regarding waste, noise, and damage. Nothing in this Section limits the right of a person with a disability to keep an assistance animal as a reasonable accommodation under applicable law."
            ]
        },

        sectionHeader("XII", "REQUIRED DISCLOSURES"),
        { text: "Lead-Based Paint Disclosure.", style: "h3" },
        { text: "Housing built before 1978 may contain lead-based paint. Lead from paint, paint chips, and dust can pose health hazards if not managed properly. Tenant acknowledges receipt of the federally required Lead Warning Statement and the EPA pamphlet \"Protect Your Family from Lead in Your Home,\" in accordance with 42 U.S.C. \u00a7 4852d and 24 C.F.R. Part 35." },
        { text: "Window Guards.", style: "h3" },
        { text: "Under New York City Health Code \u00a7 131.15, the Authority is required to provide and install approved window guards in all apartments where a child ten (10) years of age or younger resides. Tenant shall complete and return the annual Window Guard notice and shall not remove or tamper with any installed window guard." },
        { text: "Bedbug Disclosure.", style: "h3" },
        { text: "In accordance with New York Real Property Law \u00a7 235-b and applicable regulations, the Authority shall furnish the Tenant with the bedbug infestation history disclosure form (DHCR form NYC-RA-79B or successor) prior to lease execution." },
        { text: "Smoke-Free Housing.", style: "h3" },
        { text: "Pursuant to 24 C.F.R. Parts 5, 91, 92, 93, 200, 574, 882, 891, and 982 (HUD Smoke-Free Public Housing rule), the smoking of prohibited tobacco products is not permitted in any dwelling unit, indoor common area, administrative office, or within twenty-five (25) feet of any Authority building." },
        { text: "Smoke and Carbon Monoxide Detectors.", style: "h3" },
        { text: "The Premises have been equipped with operational smoke and carbon-monoxide detectors in compliance with applicable law. Tenant acknowledges receipt and shall maintain the same in working order at all times, including timely replacement of batteries." },

        sectionHeader("XIII", "DEFAULT, TERMINATION, AND REMEDIES"),
        {
            ol: [
                "Events of Default include, without limitation: (a) nonpayment of Rent or any other sum due hereunder; (b) breach of any material covenant or obligation of Tenant; (c) abandonment of the Premises; or (d) use of the Premises in violation of applicable law or this Agreement.",
                "Upon the occurrence of an Event of Default, the Authority may, in addition to all other remedies available at law or in equity, deliver to Tenant a written notice to cure and, if such default is not cured within the period stated therein (which shall be the minimum period required by applicable law, if any), commence summary proceedings for possession of the Premises.",
                "Either Party may terminate this Agreement upon not less than thirty (30) days' prior written notice to the other Party, except where a longer notice period is required by applicable law."
            ]
        },

        sectionHeader("XIV", "INSURANCE; INDEMNIFICATION; LIMITATION OF LIABILITY"),
        {
            text: "Tenant is strongly encouraged to maintain a policy of renter's insurance covering personal property and personal liability. The Authority's insurance does not cover the personal property of the Tenant. To the fullest extent permitted by law, Tenant shall indemnify, defend, and hold harmless the Authority and its officers, employees, and agents from and against any and all claims, damages, losses, and expenses (including reasonable attorneys' fees) arising out of or resulting from Tenant's use of the Premises, except to the extent caused by the negligence or willful misconduct of the Authority."
        },

        sectionHeader("XV", "EMERGENCY CONTACT"),
        {
            text: [
                "In the event of an emergency or if the Authority is otherwise unable to reach the Tenant, the Tenant authorizes the Authority to contact ",
                hi(t.tecname), " at ", hi(t.tecphn),
                ". The Authority's use of this contact information shall not constitute notice for any purpose under this Agreement."
            ]
        },

        sectionHeader("XVI", "NOTICES"),
        {
            text: [
                "All notices to the Tenant shall be deemed properly given if delivered personally or mailed by first-class mail to the Premises or to such other address as the Tenant has provided in writing. All notices to the Authority shall be delivered to the Property Management Office serving the Premises. The Tenant may also be contacted at ",
                hi(t.tphone), " or ", hi(t.temail), " for non-formal communications, provided that such methods shall not substitute for any notice required by law to be in writing."
            ]
        },

        sectionHeader("XVII", "GENERAL PROVISIONS"),
        {
            ol: [
                { text: ["\u00a0", { text: "Governing Law; Venue.", bold: true }, " This Agreement shall be governed by, and construed in accordance with, the laws of the State of New York, without regard to its conflict-of-laws principles. The Parties consent to the exclusive jurisdiction of the courts located in the City of New York."] },
                { text: ["\u00a0", { text: "Severability.", bold: true }, " If any provision of this Agreement is held to be invalid or unenforceable by a court of competent jurisdiction, the remaining provisions shall continue in full force and effect."] },
                { text: ["\u00a0", { text: "Entire Agreement; Amendments.", bold: true }, " This Agreement, together with any exhibits, schedules, and Authority rules incorporated by reference, constitutes the entire agreement between the Parties with respect to the subject matter hereof, and supersedes all prior agreements or understandings. No amendment shall be effective unless in writing and signed by both Parties."] },
                { text: ["\u00a0", { text: "Waiver.", bold: true }, " The failure of either Party to enforce any provision hereof shall not constitute a waiver of such provision or the right to enforce the same."] },
                { text: ["\u00a0", { text: "Counterparts; Electronic Signatures.", bold: true }, " This Agreement may be executed in counterparts, each of which shall be deemed an original, and electronic signatures shall be deemed valid and enforceable to the fullest extent permitted by law."] },
                { text: ["\u00a0", { text: "Headings.", bold: true }, " Section headings are for convenience only and shall not affect the construction of this Agreement."] }
            ]
        },

        // ============ ACKNOWLEDGMENT & SIGNATURES ============
        { text: "", pageBreak: "before" },
        sectionHeader("XVIII", "ACKNOWLEDGMENT AND EXECUTION"),
        {
            text: "BY SIGNING BELOW, the Parties acknowledge that they have read this Agreement, understand its terms, and intend to be legally bound by it. Tenant acknowledges receipt of a fully executed copy.",
            margin: [0, 0, 0, 24]
        },
        // Two signature blocks side by side
        {
            columns: [
                {
                    width: "*",
                    stack: [
                        { text: "TENANT", fontSize: 8, color: TEXT_MUTED, characterSpacing: 1.5, margin: [0, 0, 0, 6] },
                        { canvas: [{ type: "line", x1: 0, y1: 0, x2: 200, y2: 0, lineWidth: 0.75, lineColor: TEXT_DARK }] },
                        { text: ["Name: ", hi(tenantFullName)], margin: [0, 6, 0, 0] },
                        { text: "Signature: ____________________________", margin: [0, 16, 0, 0] },
                        { text: "Date: ____________________________", margin: [0, 10, 0, 0] }
                    ]
                },
                { width: 30, text: "" },
                {
                    width: "*",
                    stack: [
                        { text: "AUTHORIZED REPRESENTATIVE", fontSize: 8, color: TEXT_MUTED, characterSpacing: 1.5, margin: [0, 0, 0, 6] },
                        { canvas: [{ type: "line", x1: 0, y1: 0, x2: 200, y2: 0, lineWidth: 0.75, lineColor: TEXT_DARK }] },
                        { text: "For: New York City Housing Authority", margin: [0, 6, 0, 0] },
                        { text: "Name: ____________________________", margin: [0, 6, 0, 0] },
                        { text: "Title: ____________________________", margin: [0, 6, 0, 0] },
                        { text: "Signature: ____________________________", margin: [0, 10, 0, 0] },
                        { text: "Date: ____________________________", margin: [0, 10, 0, 0] }
                    ]
                }
            ],
            margin: [0, 0, 0, 30]
        },
        // Witness block
        {
            text: "WITNESS",
            fontSize: 8,
            color: TEXT_MUTED,
